package api

import (
	"errors"
	"fmt"

	"github.com/volcano-sh/agentcube/pkg/types"
	"k8s.io/apimachinery/pkg/runtime"
	"k8s.io/apimachinery/pkg/runtime/schema"
)

var (
	ErrAgentRuntimeNotFound = errors.New("agentruntime not found")
	ErrCodeInterpreterNotFound = errors.New("codeinterpreter not found")
	ErrTemplateMissing = errors.New("template missing")
	ErrPublicKeyMissing = errors.New("public key missing")
)

type APIStatus interface {
	GetGroupResource() schema.GroupResource
	GetName() string
}

type NotFoundError struct {
	GroupResource schema.GroupResource
	Name          string
}

func (e *NotFoundError) Error() string {
	return fmt.Sprintf("%s %s not found", e.GroupResource.String(), e.Name)
}

func (e *NotFoundError) GetGroupResource() schema.GroupResource {
	return e.GroupResource
}

func (e *NotFoundError) GetName() string {
	return e.Name
}

func NewAgentRuntimeNotFoundError(name, namespace string) *NotFoundError {
	return &NotFoundError{
		GroupResource: schema.GroupResource{
			Group:    "runtime.agentcube.volcano.sh",
			Resource: "agentruntimes",
		},
		Name: name,
	}
}

func NewCodeInterpreterNotFoundError(name, namespace string) *NotFoundError {
	return &NotFoundError{
		GroupResource: schema.GroupResource{
			Group:    "runtime.agentcube.volcano.sh",
			Resource: "codeinterpreters",
		},
		Name: name,
	}
}

func NewTemplateNotFoundError(kind, name, namespace string) *NotFoundError {
	group := "agentcube.volcano.sh"
	resource := "agentruntimes"
	if kind == string(types.CodeInterpreterKind) {
		resource = "codeinterpreters"
	}
	return &NotFoundError{
		GroupResource: schema.GroupResource{
			Group:    group,
			Resource: resource,
		},
		Name: name,
	}
}

func NewSessionNotFoundError(sessionID string) *NotFoundError {
	return &NotFoundError{
		GroupResource: schema.GroupResource{
			Group:    "agentcube.volcano.sh",
			Resource: "sessions",
		},
		Name: sessionID,
	}
}

type SandboxKind string

const (
	AgentRuntimeKind       SandboxKind = "AgentRuntime"
	CodeInterpreterKind   SandboxKind = "CodeInterpreter"
	SandboxKind           SandboxKind = "Sandbox"
	SandboxClaimKind      SandboxKind = "SandboxClaim"
)

func (k SandboxKind) String() string {
	return string(k)
}

func init() {
	types.SchemeBuilder = runtime.NewSchemeBuilder(types.AddKnownTypes)
	types.AddToScheme = types.SchemeBuilder.AddToScheme
}

