var ErrNotFound = errors.New("store: not found")

type Store interface {
	Ping(ctx context.Context) error
	GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error)
	StoreSandbox(ctx context.Context, sessionID string, info *SandboxInfo) error
	UpdateSandbox(ctx context.Context, sessionID string, info *SandboxInfo) error
	DeleteSandboxBySessionID(ctx context.Context, sessionID string) error
	ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]*SandboxInfo, error)
	ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]*SandboxInfo, error)
	UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error
	Close() error
}

type SandboxInfo struct {
	SandboxID       string
	Name            string
	SessionID       string
	Kind            string
	Namespace       string
	EntryPoints     []EntryPoint
	ExpiresAt       time.Time
	LastActivity    time.Time
}

type EntryPoint struct {
	Path      string
	Protocol  string
	Endpoint  string
}

const (
	sessionPrefix      = "session:"
	expiryKey         = "session:expiry"
	lastActivityKey   = "session:last_activity"
)

func sessionKey(sessionID string) string {
	return sessionPrefix + sessionID
}

package store

import (
	"context"
	"encoding/json"
	"errors"
	"os"
	"strconv"
	"strings"
	"sync"
	"time"

	"github.com/redis/go-redis/v9"
)

type redisStore struct {
	client *redis.Client
}

func NewRedisStore(addr, password string, passwordRequired bool) (Store, error) {
	if passwordRequired && password == "" {
		return nil, errors.New("redis: password is required")
	}

	client := redis.NewClient(&redis.Options{
		Addr:     addr,
		Password: password,
		DB:       0,
	})

	return &redisStore{client: client}, nil
}

func (r *redisStore) Ping(ctx context.Context) error {
	pong, err := r.client.Ping(ctx).Result()
	if err != nil {
		return err
	}
	if pong != "PONG" {
		return errors.New("redis: unexpected ping response")
	}
	return nil
}

func (r *redisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error) {
	key := sessionKey(sessionID)
	data, err := r.client.Get(ctx, key).Result()
	if err == redis.Nil {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, err
	}

	var info SandboxInfo
	if err := json.Unmarshal([]byte(data), &info); err != nil {
		return nil, err
	}
	return &info, nil
}

func (r *redisStore) StoreSandbox(ctx context.Context, sessionID string, info *SandboxInfo) error {
	if info == nil {
		return errors.New("store: sandbox info is nil")
	}
	if info.ExpiresAt.IsZero() {
		return errors.New("store: expiration time is required")
	}

	key := sessionKey(sessionID)
	data, err := json.Marshal(info)
	if err != nil {
		return err
	}

	now := time.Now().Unix()
	pipe := r.client.Pipeline()
	pipe.SetNX(ctx, key, data, 0)
	pipe.ZAdd(ctx, expiryKey, redis.Z{Score: float64(info.ExpiresAt.Unix()), Member: sessionID})
	pipe.ZAdd(ctx, lastActivityKey, redis.Z{Score: float64(now), Member: sessionID})

	_, err = pipe.Exec(ctx)
	return err
}

func (r *redisStore) UpdateSandbox(ctx context.Context, sessionID string, info *SandboxInfo) error {
	key := sessionKey(sessionID)
	data, err := json.Marshal(info)
	if err != nil {
		return err
	}

	ok, err := r.client.SetXX(ctx, key, data, 0).Result()
	if err != nil {
		return err
	}
	if !ok {
		return errors.New("store: key not exists")
	}
	return nil
}

func (r *redisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := sessionKey(sessionID)
	pipe := r.client.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, expiryKey, sessionID)
	pipe.ZRem(ctx, lastActivityKey, sessionID)

	_, err := pipe.Exec(ctx)
	return err
}

func (r *redisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]*SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

	members, err := r.client.ZRangeByScore(ctx, expiryKey, &redis.ZRangeBy{
		Min:    "-inf",
		Max:    strconv.FormatInt(before.Unix(), 10),
		Offset: 0,
		Count:  int64(limit),
	}).Result()
	if err != nil {
		return nil, err
	}

	return r.loadSandboxesBySessionIDs(ctx, members)
}

func (r *redisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]*SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

	members, err := r.client.ZRangeByScore(ctx, lastActivityKey, &redis.ZRangeBy{
		Min:    "-inf",
		Max:    strconv.FormatInt(before.Unix(), 10),
		Offset: 0,
		Count:  int64(limit),
	}).Result()
	if err != nil {
		return nil, err
	}

	return r.loadSandboxesBySessionIDs(ctx, members)
}

func (r *redisStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = sessionKey(id)
	}

	results, err := r.client.MGet(ctx, keys...).Result()
	if err != nil {
		return nil, err
	}

	var sandboxes []*SandboxInfo
	for i, result := range results {
		if result == nil {
			continue
		}
		var info SandboxInfo
		if err := json.Unmarshal([]byte(result.(string)), &info); err != nil {
			continue
		}
		sandboxes = append(sandboxes, &info)
		_ = i
	}
	return sandboxes, nil
}

func (r *redisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return errors.New("store: session id is required")
	}

	if at.IsZero() {
		at = time.Now()
	}

	key := sessionKey(sessionID)
	exists, err := r.client.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	return r.client.ZAdd(ctx, lastActivityKey, redis.Z{Score: float64(at.Unix()), Member: sessionID}).Err()
}

func (r *redisStore) Close() error {
	return r.client.Close()
}

