	"github.com/gin-gonic/gin"
	"github.com/google/uuid"
	"github.com/volcano-sh/agentcube/pkg/store"
	"k8s.io/klog/v2"
)

const (
	DefaultSessionTimeout     = 15 * time.Minute
	DefaultMaxSessionDuration = 8 * time.Hour
	DefaultSandboxIdleTimeout = 15 * time.Minute
)

type Config struct {
	Addr          string
	EnableAuth    bool
	EnableTLS     bool
	CertFile      string
	KeyFile       string
	RedisAddr     string
	RedisPassword string
}

type CreateSandboxRequest struct {
	Kind      string `json:"kind"`
	Name      string `json:"name"`
	Namespace string `json:"namespace"`
}

type CreateSandboxResponse struct {
	SessionID   string       `json:"sessionId"`
	SandboxID   string       `json:"sandboxId"`
	SandboxName string       `json:"sandboxName"`
	EntryPoints []EntryPoint `json:"entryPoints"`
}

type EntryPoint struct {
	Path     string `json:"path"`
	Protocol string `json:"protocol"`
	Endpoint string `json:"endpoint"`
}

type WorkloadManager struct {
	store  store.Store
	config *Config
	router *gin.Engine
	server *http.Server
	ctx    context.Context
	cancel context.CancelFunc
	wg     sync.WaitGroup
}

func NewWorkloadManager(config *Config) (*WorkloadManager, error) {
	ctx, cancel := context.WithCancel(context.Background())

	s := store.Storage()
	if s == nil {
		return nil, fmt.Errorf("store not initialized")
	}

	if err := s.Ping(ctx); err != nil {
		return nil, fmt.Errorf("failed to ping store: %w", err)
	}

	wm := &WorkloadManager{
		store:  s,
		config: config,
		ctx:    ctx,
		cancel: cancel,
	}

	wm.setupRouter()
	return wm, nil
}

func (wm *WorkloadManager) setupRouter() {
	if wm.config.EnableTLS {
		gin.SetMode(gin.ReleaseMode)
	}

	wm.router = gin.New()
	wm.router.Use(gin.Recovery())
	wm.router.Use(gin.Logger())

	wm.router.GET("/health", wm.handleHealth)

	v1 := wm.router.Group("/v1")
	if wm.config.EnableAuth {
		v1.Use(wm.authMiddleware())
	}
	v1.Use(wm.loggingMiddleware())

	v1.POST("/agent-runtime", wm.handleCreateAgentRuntime)
	v1.DELETE("/agent-runtime/sessions/:sessionId", wm.handleDeleteAgentRuntimeSession)
	v1.POST("/code-interpreter", wm.handleCreateCodeInterpreter)
	v1.DELETE("/code-interpreter/sessions/:sessionId", wm.handleDeleteCodeInterpreterSession)
}

func (wm *WorkloadManager) loggingMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		path := c.Request.URL.Path
		c.Next()
		latency := time.Since(start)
		status := c.Writer.Status()
		klog.V(2).Infof("[%d] %s %s %s", status, c.Request.Method, path, latency)
	}
}

func (wm *WorkloadManager) authMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"message": "Missing authorization header"})
			return
		}

		parts := splitAuthHeader(authHeader)
		if len(parts) != 2 {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"message": "Invalid authorization header format"})
			return
		}

		c.Set("token", parts[1])
		c.Next()
	}
}

func splitAuthHeader(header string) []string {
	var parts []string
	current := ""
	for _, ch := range header {
		if ch == ' ' {
			if current != "" {
				parts = append(parts, current)
				current = ""
			}
		} else {
			current += string(ch)
		}
	}
	if current != "" {
		parts = append(parts, current)
	}
	return parts
}

func (wm *WorkloadManager) handleHealth(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "healthy"})
}

func (wm *WorkloadManager) handleCreateAgentRuntime(c *gin.Context) {
	wm.createSandbox(c, "AgentRuntime")
}

func (wm *WorkloadManager) handleCreateCodeInterpreter(c *gin.Context) {
	wm.createSandbox(c, "CodeInterpreter")
}

func (wm *WorkloadManager) createSandbox(c *gin.Context, kind string) {
	var req CreateSandboxRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"message": "Invalid request body"})
		return
	}

	req.Kind = kind

	if err := validateCreateRequest(req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"message": err.Error()})
		return
	}

	sessionID := uuid.New().String()
	sandboxID := uuid.New().String()

	now := time.Now()
	expiresAt := now.Add(DefaultMaxSessionDuration)

	info := &store.SandboxInfo{
		SandboxID:    sandboxID,
		Name:         req.Name,
		SessionID:    sessionID,
		Kind:         req.Kind,
		Namespace:    req.Namespace,
		EntryPoints:  []store.EntryPoint{},
		ExpiresAt:    expiresAt,
		LastActivity: now,
	}

	if err := wm.store.StoreSandbox(c.Request.Context(), sessionID, info); err != nil {
		klog.Errorf("Failed to store sandbox: %v", err)
		c.JSON(http.StatusInternalServerError, gin.H{"message": "internal server error"})
		return
	}

	resp := CreateSandboxResponse{
		SessionID:   sessionID,
		SandboxID:   sandboxID,
		SandboxName: req.Name,
		EntryPoints: []EntryPoint{},
	}

	c.JSON(http.StatusOK, resp)
}

func validateCreateRequest(req CreateSandboxRequest) error {
	if req.Kind != "AgentRuntime" && req.Kind != "CodeInterpreter" {
		return fmt.Errorf("invalid kind: must be AgentRuntime or CodeInterpreter")
	}
	if req.Namespace == "" {
		return fmt.Errorf("namespace is required")
	}
	if req.Name == "" {
		return fmt.Errorf("name is required")
	}
	return nil
}

func (wm *WorkloadManager) handleDeleteAgentRuntimeSession(c *gin.Context) {
	wm.deleteSandboxSession(c, "AgentRuntime")
}

func (wm *WorkloadManager) handleDeleteCodeInterpreterSession(c *gin.Context) {
	wm.deleteSandboxSession(c, "CodeInterpreter")
}

func (wm *WorkloadManager) deleteSandboxSession(c *gin.Context, kind string) {
	sessionID := c.Param("sessionId")

	info, err := wm.store.GetSandboxBySessionID(c.Request.Context(), sessionID)
	if err != nil {
		if err == store.ErrNotFound {
			c.JSON(http.StatusNotFound, gin.H{"message": fmt.Sprintf("Session ID %s not found, maybe already deleted", sessionID)})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"message": "internal server error"})
		return
	}

	if err := wm.store.DeleteSandboxBySessionID(c.Request.Context(), sessionID); err != nil {
		klog.Errorf("Failed to delete session: %v", err)
		c.JSON(http.StatusInternalServerError, gin.H{"message": "internal server error"})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "Sandbox deleted successfully"})
	_ = info
}

func (wm *WorkloadManager) Start() error {
	wm.server = &http.Server{
		Addr:        wm.config.Addr,
		Handler:     wm.router,
		ReadTimeout: 15 * time.Second,
		IdleTimeout: 90 * time.Second,
	}

	go func() {
		klog.Infof("Starting workload manager on %s", wm.config.Addr)
		if wm.config.EnableTLS {
			if wm.config.CertFile == "" || wm.config.KeyFile == "" {
				return
			}
			if err := wm.server.ListenAndServeTLS(wm.config.CertFile, wm.config.KeyFile); err != nil && err != http.ErrServerClosed {
				klog.Errorf("Server error: %v", err)
			}
		} else {
			if err := wm.server.ListenAndServe(); err != nil && err != http.ErrServerClosed {
				klog.Errorf("Server error: %v", err)
			}
		}
	}()

	wm.startGCTask()
	return nil
}

func (wm *WorkloadManager) startGCTask() {
	wm.wg.Add(1)
	go func() {
		defer wm.wg.Done()
		ticker := time.NewTicker(15 * time.Second)
		defer ticker.Stop()

		for {
			select {
			case <-wm.ctx.Done():
				return
			case <-ticker.C:
				wm.runGC()
			}
		}
	}()
}

func (wm *WorkloadManager) runGC() {
	ctx, cancel := context.WithTimeout(wm.ctx, 2*time.Minute)
	defer cancel()

	inactiveCutoff := time.Now().Add(-DefaultSandboxIdleTimeout)
	inactive, err := wm.store.ListInactiveSandboxes(ctx, inactiveCutoff, 16)
	if err != nil {
		klog.Errorf("Failed to list inactive sandboxes: %v", err)
	}

	expired, err := wm.store.ListExpiredSandboxes(ctx, time.Now(), 16)
	if err != nil {
		klog.Errorf("Failed to list expired sandboxes: %v", err)
	}

	deleted := make(map[string]bool)
	for _, s := range inactive {
		if !deleted[s.SessionID] {
			if err := wm.store.DeleteSandboxBySessionID(ctx, s.SessionID); err != nil {
				klog.Errorf("Failed to delete inactive sandbox: %v", err)
			} else {
				deleted[s.SessionID] = true
			}
		}
	}
	for _, s := range expired {
		if !deleted[s.SessionID] {
			if err := wm.store.DeleteSandboxBySessionID(ctx, s.SessionID); err != nil {
				klog.Errorf("Failed to delete expired sandbox: %v", err)
			} else {
				deleted[s.SessionID] = true
			}
		}
	}
}

func (wm *WorkloadManager) Stop() error {
	klog.Info("Stopping workload manager")
	wm.cancel()

	shutdownCtx, cancel := context.WithTimeout(context.Background(), 15*time.Second)
	defer cancel()

	if wm.server != nil {
		if err := wm.server.Shutdown(shutdownCtx); err != nil {
			klog.Errorf("Server shutdown error: %v", err)
		}
	}

	wm.wg.Wait()
	if err := wm.store.Close(); err != nil {
		klog.Errorf("Store close error: %v", err)
	}
	return nil
}

func main() {
	klog.InitFlags(nil)
	defer klog.Flush()

	config := &Config{
		Addr:          os.Getenv("ADDR"),
		EnableAuth:    os.Getenv("ENABLE_AUTH") == "true",
		EnableTLS:     os.Getenv("ENABLE_TLS") == "true",
		CertFile:      os.Getenv("TLS_CERT_FILE"),
		KeyFile:       os.Getenv("TLS_KEY_FILE"),
		RedisAddr:     os.Getenv("REDIS_ADDR"),
		RedisPassword: os.Getenv("REDIS_PASSWORD"),
	}

	if config.Addr == "" {
		config.Addr = ":8080"
	}

	if err := store.InitStore(); err != nil {
		klog.Fatalf("Failed to initialize store: %v", err)
	}

	wm, err := NewWorkloadManager(config)
	if err != nil {
		klog.Fatalf("Failed to create workload manager: %v", err)
	}

	if err := wm.Start(); err != nil {
		klog.Fatalf("Failed to start workload manager: %v", err)
	}

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)
	<-sigCh

	if err := wm.Stop(); err != nil {
		klog.Errorf("Error during shutdown: %v", err)
	}
}

