package main

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"net/http/httputil"
	"net/url"
	"os"
	"os/signal"
	"strings"
	"sync"
	"syscall"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/golang-jwt/jwt/v5"
	"github.com/google/uuid"
	"github.com/volcano-sh/agentcube/pkg/store"
	"k8s.io/klog/v2"
)

const (
	DefaultMaxConcurrentRequests = 1000
)

type Config struct {
	Port                    int
	WorkloadManagerURL      string
	RedisAddr               string
	RedisPassword           string
	EnableTLS               bool
	CertFile                string
	KeyFile                 string
	MaxConcurrentRequests   int
	AgentCubeNamespace      string
}

type SessionManager struct {
	store             store.Store
	workloadManagerURL string
	httpClient        *http.Client
	jwtManager        *JWTManager
}

func NewSessionManager(store store.Store, workloadManagerURL string) (*SessionManager, error) {
	if workloadManagerURL == "" {
		return nil, fmt.Errorf("WORKLOAD_MANAGER_URL environment variable is not set")
	}

	sm := &SessionManager{
		store:              store,
		workloadManagerURL: workloadManagerURL,
		httpClient: &http.Client{
			Timeout: 30 * time.Second,
		},
	}

	token, err := loadServiceAccountToken()
	if err == nil && token != "" {
		sm.httpClient.Transport = &tokenTransport{token: token}
	}

	return sm, nil
}

type tokenTransport struct {
	token string
}

func (t *tokenTransport) RoundTrip(req *http.Request) (*http.Response, error) {
	req.Header.Set("Authorization", "Bearer "+t.token)
	return http.DefaultTransport.RoundTrip(req)
}

func loadServiceAccountToken() (string, error) {
	data, err := os.ReadFile("/var/run/secrets/kubernetes.io/serviceaccount/token")
	if err != nil {
		return "", err
	}
	return strings.TrimSpace(string(data)), nil
}

type CreateSandboxRequest struct {
	Kind      string `json:"kind"`
	Name      string `json:"name"`
	Namespace string `json:"namespace"`
}

type CreateSandboxResponse struct {
	SessionID    string       `json:"sessionId"`
	SandboxID    string       `json:"sandboxId"`
	SandboxName  string       `json:"sandboxName"`
	EntryPoints  []EntryPoint `json:"entryPoints"`
}

type EntryPoint struct {
	Path      string `json:"path"`
	Protocol  string `json:"protocol"`
	Endpoint  string `json:"endpoint"`
}

type JWTManager struct {
	signingKey []byte
}

func NewJWTManager(privateKeyPath string) (*JWTManager, error) {
	keyData, err := os.ReadFile(privateKeyPath)
	if err != nil {
		return nil, err
	}
	return &JWTManager{signingKey: keyData}, nil
}

func (m *JWTManager) GenerateToken(claims jwt.MapClaims) (string, error) {
	token := jwt.NewWithClaims(jwt.SigningMethodRS256, claims)
	return token.SignedString(m.signingKey)
}

type Router struct {
	sessionManager    *SessionManager
	concurrencyLimit  chan struct{}
	server            *http.Server
	config            *Config
	jwtManager        *JWTManager
	ctx               context.Context
	cancel            context.CancelFunc
	wg                sync.WaitGroup
}

func NewRouter(config *Config) (*Router, error) {
	ctx, cancel := context.WithCancel(context.Background())

	s := store.Storage()
	if s == nil {
		return nil, fmt.Errorf("store not initialized")
	}

	sm, err := NewSessionManager(s, config.WorkloadManagerURL)
	if err != nil {
		return nil, err
	}

	limit := config.MaxConcurrentRequests
	if limit <= 0 {
		limit = DefaultMaxConcurrentRequests
	}

	router := &Router{
		sessionManager:   sm,
		concurrencyLimit: make(chan struct{}, limit),
		config:           config,
		ctx:              ctx,
		cancel:           cancel,
	}

	router.setupRouter()
	return router, nil
}

func (r *Router) setupRouter() {
	gin.SetMode(gin.ReleaseMode)
	r.server = &http.Server{
		Addr:         fmt.Sprintf(":%d", r.config.Port),
		Handler:      r.router(),
		ReadTimeout:  30 * time.Second,
		IdleTimeout:  90 * time.Second,
	}
}

func (r *Router) router() *gin.Engine {
	engine := gin.New()
	engine.Use(gin.Recovery())
	engine.Use(gin.Logger())

	engine.GET("/health/live", r.handleHealthLive)
	engine.GET("/health/ready", r.handleHealthReady)

	v1 := engine.Group("/v1")
	v1.Use(r.concurrencyMiddleware())
	v1.Use(gin.Logger())

	v1.GET("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", r.handleInvoke)
	v1.POST("/namespaces/:namespace/agent-runtimes/:name/invocations/*path", r.handleInvoke)
	v1.GET("/namespaces/:namespace/code-interpreters/:name/invocations/*path", r.handleInvoke)
	v1.POST("/namespaces/:namespace/code-interpreters/:name/invocations/*path", r.handleInvoke)

	return engine
}

func (r *Router) concurrencyMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		select {
		case r.concurrencyLimit <- struct{}{}:
			defer func() { <-r.concurrencyLimit }()
			c.Next()
		default:
			c.JSON(http.StatusTooManyRequests, gin.H{
				"error": "server overloaded, please try again later",
				"code":  "SERVER_OVERLOADED",
			})
			c.Abort()
		}
	}
}

func (r *Router) handleHealthLive(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "alive"})
}

func (r *Router) handleHealthReady(c *gin.Context) {
	if r.sessionManager == nil {
		c.JSON(http.StatusServiceUnavailable, gin.H{
			"status": "not ready",
			"error":  "session manager not available",
		})
		return
	}
	c.JSON(http.StatusOK, gin.H{"status": "ready"})
}

func (r *Router) handleInvoke(c *gin.Context) {
	namespace := c.Param("namespace")
	name := c.Param("name")
	path := c.Param("path")
	kind := c.Query("kind")
	if kind == "" {
		kind = "AgentRuntime"
	}

	sessionID := c.GetHeader("x-agentcube-session-id")
	if sessionID == "" {
		resp, err := r.createSandbox(c.Request.Context(), kind, name, namespace)
		if err != nil {
			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
			return
		}
		sessionID = resp.SessionID

		info := &store.SandboxInfo{
			SandboxID:    resp.SandboxID,
			Name:         resp.SandboxName,
			SessionID:    resp.SessionID,
			Kind:         kind,
			Namespace:    namespace,
			EntryPoints:  toStoreEntryPoints(resp.EntryPoints),
			ExpiresAt:    time.Now().Add(8 * time.Hour),
			LastActivity: time.Now(),
		}
		r.sessionManager.store.StoreSandbox(c.Request.Context(), sessionID, info)
	}

	info, err := r.sessionManager.store.GetSandboxBySessionID(c.Request.Context(), sessionID)
	if err != nil {
		if err == store.ErrNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": fmt.Sprintf("session %s not found", sessionID)})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": "failed to get session"})
		return
	}

	r.sessionManager.store.UpdateSessionLastActivity(c.Request.Context(), sessionID, time.Now())

	proxy := r.createProxy(info)
	proxy.ServeHTTP(c.Writer, c.Request)

	r.sessionManager.store.UpdateSessionLastActivity(c.Request.Context(), sessionID, time.Now())
}

func (r *Router) createSandbox(ctx context.Context, kind, name, namespace string) (*CreateSandboxResponse, error) {
	reqBody := CreateSandboxRequest{
		Kind:      kind,
		Name:      name,
		Namespace: namespace,
	}
	body, _ := json.Marshal(reqBody)

	req, err := http.NewRequestWithContext(ctx, "POST", r.sessionManager.workloadManagerURL+"/v1/"+strings.ToLower(kind)+"s", strings.NewReader(string(body)))
	if err != nil {
		return nil, err
	}
	req.Header.Set("Content-Type", "application/json")

	resp, err := r.sessionManager.httpClient.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		var errResp map[string]string
		json.NewDecoder(resp.Body).Decode(&errResp)
		return nil, fmt.Errorf("%s", errResp["message"])
	}

	var result CreateSandboxResponse
	if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
		return nil, err
	}

	if result.SessionID == "" {
		return nil, fmt.Errorf("invalid response: missing session id")
	}

	return &result, nil
}

func (r *Router) createProxy(info *store.SandboxInfo) *httputil.ReverseProxy {
	var target *url.URL
	if len(info.EntryPoints) > 0 {
		ep := info.EntryPoints[0]
		scheme := "http"
		if ep.Protocol == "https" {
			scheme = "https"
		}
		target, _ = url.Parse(scheme + "://" + ep.Endpoint)
	}

	proxy := httputil.NewSingleHostReverseProxy(target)
	proxy.Director = func(req *http.Request) {
		req.URL.Scheme = target.Scheme
		req.URL.Host = target.Host
		req.Host = target.Host

		req.Header.Set("X-Forwarded-Host", req.Host)
		if req.TLS != nil {
			req.Header.Set("X-Forwarded-Proto", "https")
		} else {
			req.Header.Set("X-Forwarded-Proto", "http")
		}
		clientIP := strings.Split(req.RemoteAddr, ":")[0]
		req.Header.Set("X-Forwarded-For", clientIP)
	}
	return proxy
}

func (r *Router) Start() error {
	klog.Infof("Starting router on port %d", r.config.Port)

	if r.config.EnableTLS {
		return r.server.ListenAndServeTLS(r.config.CertFile, r.config.KeyFile)
	}
	return r.server.ListenAndServe()
}

func (r *Router) Stop() error {
	klog.Info("Stopping router")
	r.cancel()

	shutdownCtx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	return r.server.Shutdown(shutdownCtx)
}

func toStoreEntryPoints(eps []EntryPoint) []store.EntryPoint {
	result := make([]store.EntryPoint, len(eps))
	for i, ep := range eps {
		result[i] = store.EntryPoint{
			Path:     ep.Path,
			Protocol: ep.Protocol,
			Endpoint: ep.Endpoint,
		}
	}
	return result
}

func main() {
	klog.InitFlags(nil)
	defer klog.Flush()

	port := 8080
	fmt.Sscanf(os.Getenv("PORT"), "%d", &port)

	config := &Config{
		Port:                  port,
		WorkloadManagerURL:   os.Getenv("WORKLOAD_MANAGER_URL"),
		RedisAddr:            os.Getenv("REDIS_ADDR"),
