		return err
	}
	if pong != "PONG" {
		return errors.New("valkey: unexpected ping response")
	}
	return nil
}

func (v *valkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*SandboxInfo, error) {
	key := sessionKey(sessionID)
	data, err := v.client.Get(ctx, key).Result()
	if err == redis.Nil {
		return nil, ErrNotFound
	}
	if err != nil {
		return nil, err
	}

	var info SandboxInfo
	if err := json.Unmarshal([]byte(data), &info); err != nil {
		return nil, err
	}
	return &info, nil
}

func (v *valkeyStore) StoreSandbox(ctx context.Context, sessionID string, info *SandboxInfo) error {
	if info == nil {
		return errors.New("store: sandbox info is nil")
	}
	if info.ExpiresAt.IsZero() {
		return errors.New("store: expiration time is required")
	}

	key := sessionKey(sessionID)
	data, err := json.Marshal(info)
	if err != nil {
		return err
	}

	now := time.Now().Unix()
	pipe := v.client.Pipeline()
	pipe.SetNX(ctx, key, data, 0)
	pipe.ZAdd(ctx, expiryKey, redis.Z{Score: float64(info.ExpiresAt.Unix()), Member: sessionID})
	pipe.ZAdd(ctx, lastActivityKey, redis.Z{Score: float64(now), Member: sessionID})

	_, err = pipe.Exec(ctx)
	return err
}

func (v *valkeyStore) UpdateSandbox(ctx context.Context, sessionID string, info *SandboxInfo) error {
	key := sessionKey(sessionID)
	data, err := json.Marshal(info)
	if err != nil {
		return err
	}

	ok, err := v.client.SetXX(ctx, key, data, 0).Result()
	if err != nil {
		return err
	}
	if !ok {
		return errors.New("store: key not exists")
	}
	return nil
}

func (v *valkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := sessionKey(sessionID)
	pipe := v.client.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, expiryKey, sessionID)
	pipe.ZRem(ctx, lastActivityKey, sessionID)

	_, err := pipe.Exec(ctx)
	return err
}

func (v *valkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int) ([]*SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

	members, err := v.client.ZRangeByScore(ctx, expiryKey, &redis.ZRangeBy{
		Min:    "-inf",
		Max:    strconv.FormatInt(before.Unix(), 10),
		Offset: 0,
		Count:  int64(limit),
	}).Result()
	if err != nil {
		return nil, err
	}

	return v.loadSandboxesBySessionIDs(ctx, members)
}

func (v *valkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int) ([]*SandboxInfo, error) {
	if limit <= 0 {
		return nil, nil
	}

	members, err := v.client.ZRangeByScore(ctx, lastActivityKey, &redis.ZRangeBy{
		Min:    "-inf",
		Max:    strconv.FormatInt(before.Unix(), 10),
		Offset: 0,
		Count:  int64(limit),
	}).Result()
	if err != nil {
		return nil, err
	}

	return v.loadSandboxesBySessionIDs(ctx, members)
}

func (v *valkeyStore) loadSandboxesBySessionIDs(ctx context.Context, sessionIDs []string) ([]*SandboxInfo, error) {
	if len(sessionIDs) == 0 {
		return nil, nil
	}

	keys := make([]string, len(sessionIDs))
	for i, id := range sessionIDs {
		keys[i] = sessionKey(id)
	}

	results, err := v.client.MGet(ctx, keys...).Result()
	if err != nil {
		return nil, err
	}

	var sandboxes []*SandboxInfo
	for i, result := range results {
		if result == nil {
			continue
		}
		var info SandboxInfo
		if err := json.Unmarshal([]byte(result.(string)), &info); err != nil {
			continue
		}
		sandboxes = append(sandboxes, &info)
		_ = i
	}
	return sandboxes, nil
}

func (v *valkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	if sessionID == "" {
		return errors.New("store: session id is required")
	}

	if at.IsZero() {
		at = time.Now()
	}

	key := sessionKey(sessionID)
	exists, err := v.client.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	return v.client.ZAdd(ctx, lastActivityKey, redis.Z{Score: float64(at.Unix()), Member: sessionID}).Err()
}

func (v *valkeyStore) Close() error {
	return v.client.Close()
}

var (
	store     Store
	storeOnce sync.Once
	storeErr  error
)

func Storage() Store {
	storeOnce.Do(func() {
		storeType := strings.ToLower(os.Getenv("STORE_TYPE"))
		if storeType == "" {
			storeType = "redis"
		}

		switch storeType {
		case "redis":
			addr := os.Getenv("REDIS_ADDR")
			if addr == "" {
				storeErr = errors.New("store: REDIS_ADDR is required")
				return
			}
			password := os.Getenv("REDIS_PASSWORD")
			passwordRequired := strings.ToLower(os.Getenv("REDIS_PASSWORD_REQUIRED")) != "false"
			store, storeErr = NewRedisStore(addr, password, passwordRequired)
		case "valkey":
			addr := os.Getenv("VALKEY_ADDR")
			if addr == "" {
				storeErr = errors.New("store: VALKEY_ADDR is required")
				return
			}
			password := os.Getenv("VALKEY_PASSWORD")
			passwordRequired := strings.ToLower(os.Getenv("VALKEY_PASSWORD_REQUIRED")) != "false"
			_ = strings.ToLower(os.Getenv("VALKEY_DISABLE_CACHE")) == "true"
			_ = strings.ToLower(os.Getenv("VALKEY_FORCE_SINGLE")) == "true"
			addrs := strings.Split(addr, ",")
			store, storeErr = NewValkeyStore(addrs, password, passwordRequired, false, false)
		default:
			storeErr = errors.New("store: unsupported store type")
		}
	})
	return store
}

func InitStore() error {
	_ = Storage()
	return storeErr
}

