	agentv1 "sigs.k8s.io/agent-sandbox/api/v1alpha1"
	"k8s.io/klog/v2"
)

const (
	LastActivityAnnotationKey = "last-activity-time"
	SessionExpirationTimeout  = 15 * time.Minute
)

type Reconciler struct {
	client client.Client
	scheme *runtime.Scheme
}

func NewReconciler(client client.Client, scheme *runtime.Scheme) *Reconciler {
	return &Reconciler{
		client: client,
		scheme: scheme,
	}
}

func (r *Reconciler) Reconcile(ctx context.Context, req ctrl.Request) (ctrl.Result, error) {
	klog.Infof("Reconciling Sandbox %s/%s", req.Namespace, req.Name)

	var sandbox agentv1.Sandbox
	if err := r.client.Get(ctx, req.NamespacedName, &sandbox); err != nil {
		if client.IsNotFound(err) {
			return ctrl.Result{}, nil
		}
		return ctrl.Result{}, err
	}

	lastActivityStr, ok := sandbox.Annotations[LastActivityAnnotationKey]
	if !ok || lastActivityStr == "" {
		klog.V(4).Infof("Sandbox %s/%s has no last-activity-time annotation, skipping", req.Namespace, req.Name)
		return ctrl.Result{}, nil
	}

	lastActivity, err := time.Parse(time.RFC3339, lastActivityStr)
	if err != nil {
		klog.Errorf("Failed to parse last-activity-time for sandbox %s/%s: %v", req.Namespace, req.Name, err)
		return ctrl.Result{RequeueAfter: 30 * time.Second}, err
	}

	expirationTime := lastActivity.Add(SessionExpirationTimeout)
	if time.Now().After(expirationTime) {
		klog.Infof("Deleting expired sandbox %s/%s (last activity: %v)", req.Namespace, req.Name, lastActivity)
		if err := r.client.Delete(ctx, &sandbox); err != nil {
			if client.IsNotFound(err) {
				return ctrl.Result{}, nil
			}
			return ctrl.Result{}, err
		}
		return ctrl.Result{}, nil
	}

	requeueTime := time.Until(expirationTime)
	klog.V(4).Infof("Sandbox %s/%s expires in %v, requeueing", req.Namespace, req.Name, requeueTime)
	return ctrl.Result{RequeueAfter: requeueTime}, nil
}

func (r *Reconciler) SetupWithManager(mgr manager.Manager) error {
	return ctrl.NewControllerManagedBy(mgr).
		For(&agentv1.Sandbox{}).
		Complete(r)
}

func main() {
	klog.InitFlags(nil)
	flag.Parse()
	defer klog.Flush()

	scheme := runtime.NewScheme()
	if err := agentv1.AddToScheme(scheme); err != nil {
		klog.Fatalf("Failed to add agentv1 scheme: %v", err)
	}

	cfg, err := config.GetConfig()
	if err != nil {
		klog.Fatalf("Failed to get config: %v", err)
	}

	mgr, err := manager.New(cfg, manager.Options{
		Scheme:             scheme,
		MetricsBindAddress: "0",
		HealthProbeBindAddress: "0",
	})
	if err != nil {
		klog.Fatalf("Failed to create manager: %v", err)
	}

	reconciler := NewReconciler(mgr.GetClient(), scheme)
	if err := reconciler.SetupWithManager(mgr); err != nil {
		klog.Fatalf("Failed to setup reconciler: %v", err)
	}

	ctx := ctrl.SetupSignalHandler()
	klog.Info("Starting agentd")
	if err := mgr.Start(ctx); err != nil {
		klog.Fatalf("Failed to start manager: %v", err)
	}
}

