func (s *Server) handleExecute(c *gin.Context) {
	var req ExecuteRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error(), "code": 400})
		return
	}

	if len(req.Command) == 0 {
		c.JSON(http.StatusBadRequest, gin.H{"error": "command cannot be empty", "code": 400})
		return
	}

	timeout := DefaultTimeout
	if req.Timeout != "" {
		var err error
		timeout, err = time.ParseDuration(req.Timeout)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{
				"error": fmt.Sprintf("invalid timeout format: %s", req.Timeout),
				"code":  400,
			})
			return
		}
	}

	cmd := s.buildCommand(req)
	if req.WorkingDir != "" {
		dir, err := s.sanitizePath(req.WorkingDir)
		if err != nil {
			c.JSON(http.StatusBadRequest, gin.H{
				"error": fmt.Sprintf("Invalid working directory: %s", err.Error()),
				"code":  400,
			})
			return
		}
		cmd.Dir = dir
	}

	startTime := time.Now()
	done := make(chan error, 1)
	var stdout, stderr strings.Builder
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	go func() {
		done <- cmd.Run()
	}()

	select {
	case err := <-done:
		exitCode := 0
		responseStderr := stderr.String()
		if err != nil {
			if exitErr, ok := err.(*exec.ExitError); ok {
				exitCode = exitErr.ExitCode()
			} else {
				exitCode = 1
			}
		}

		c.JSON(http.StatusOK, ExecuteResponse{
			Stdout:    stdout.String(),
			Stderr:    responseStderr,
			ExitCode:  exitCode,
			Duration:  time.Since(startTime).Seconds(),
			StartTime: startTime.Format(time.RFC3339),
			EndTime:   time.Now().Format(time.RFC3339),
		})
	case <-time.After(timeout):
		cmd.Process.Kill()
		<-done
		c.JSON(http.StatusOK, ExecuteResponse{
			Stdout:    stdout.String(),
			Stderr:    fmt.Sprintf("command timed out after %v", timeout),
			ExitCode:  TimeoutExitCode,
			Duration:  timeout.Seconds(),
			StartTime: startTime.Format(time.RFC3339),
			EndTime:   time.Now().Format(time.RFC3339),
		})
	}
